class TicTacToe:
    def __init__(self, n):
        self.n, self.r, self.c, self.d, self.ad = n, [0]*n, [0]*n, 0, 0
    def move(self, row, col, p):
        v = 1 if p == 1 else -1
        self.r[row]+=v; self.c[col]+=v
        if row==col: self.d+=v
        if row+col==self.n-1: self.ad+=v
        if any(abs(x)==self.n for x in [self.r[row], self.c[col], self.d, self.ad]): return p
        return 0

